objects.draw:
function(ctx, obj) {
\
        ctx.save();
\

\
        // === ROLDANA (com rotação) ===
\
        ctx.translate(obj.x, obj.y);
\
        ctx.rotate(obj.rotationAngle || 0);
\
        ctx.translate(-obj.x, -obj.y);
\

\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, obj.w, 0, Math.PI * 2);
\
        ctx.fillStyle = '#cbd5e1';
\
        ctx.fill();
\
        ctx.strokeStyle = '#475569';
\
        ctx.lineWidth = 2;
\
        ctx.stroke();
\

\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, obj.w - 5, 0, Math.PI * 2);
\
        ctx.fillStyle = '#1e293b';
\
        ctx.fill();
\

\
        ctx.restore();
\

\
        // === CORDA (SEM rotação) ===
\
        if (!obj.leftMassObj || !obj.rightMassObj) return;
\

\
        const left = obj.leftMassObj;
\
        const right = obj.rightMassObj;
\

\
        const leftTop = left.y - left.w;
\
        const rightTop = right.y - right.w;
\

\
        const leftX = obj.x - obj.w;
\
        const rightX = obj.x + obj.w;
\

\
        ctx.beginPath();
\

\
        // lado esquerdo
\
        ctx.moveTo(leftX, obj.y);
\
        ctx.lineTo(leftX, leftTop);
\

\
        // conexão massa esquerda
\
        ctx.lineTo(left.x, leftTop);
\

\
        // lado direito
\
        ctx.moveTo(rightX, obj.y);
\
        ctx.lineTo(rightX, rightTop);
\

\
        // conexão massa direita
\
        ctx.lineTo(right.x, rightTop);
\

\
        ctx.strokeStyle = obj.ropeColor;
\
        ctx.lineWidth = obj.ropeWidth;
\
        ctx.lineCap = 'round';
\
        ctx.stroke();
\
      }

objects.update:
function(obj, dt) {
\
        if (!obj.leftMassObj || !obj.rightMassObj) return;
\

\
        const m1 = obj.leftMassObj.mass;
\
        const m2 = obj.rightMassObj.mass;
\
        const g = Lab.state.gravity;
\
        const r = obj.w / 100;
\
        const I = obj.momentOfInertia;
\

\
        const denom = m1 + m2 + I/(r*r);
\
        let a = (m2 - m1) * g / denom;
\

\
        // atrito
\
        if (Math.abs(obj.velocity) > 0.01) {
\
          const f = obj.friction * (m1 + m2) * g;
\
          const af = f / denom;
\
          if (a > 0) a = Math.max(0, a - af);
\
          else a = Math.min(0, a + af);
\
        }
\

\
        obj.velocity += a * dt;
\
        obj.velocity *= (1 - obj.friction * dt);
\

\
        obj.angularVelocity += (a / r) * dt;
\
        obj.angularVelocity *= (1 - obj.ropeFriction * dt);
\

\
        obj.rotationAngle += obj.angularVelocity * dt * 30;
\

\
        obj.leftPosition -= obj.velocity * dt;
\
        obj.rightPosition += obj.velocity * dt;
\

\
        const minY = 100;
\
        const maxY = 600;
\

\
        obj.leftPosition = Math.max(minY, Math.min(maxY, obj.leftPosition));
\
        obj.rightPosition = Math.max(minY, Math.min(maxY, obj.rightPosition));
\

\
        obj.leftMassObj.y = obj.leftPosition;
\
        obj.rightMassObj.y = obj.rightPosition;
\
      }

objects.draw:
function(ctx, obj) {
\
        ctx.save();
\

\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, obj.w, 0, Math.PI * 2);
\
        ctx.fillStyle = obj.fill;
\
        ctx.fill();
\

\
        // gancho
\
        ctx.beginPath();
\
        ctx.moveTo(obj.x, obj.y - obj.w);
\
        ctx.lineTo(obj.x, obj.y - obj.w - 10);
\
        ctx.stroke();
\

\
        ctx.fillStyle = '#fff';
\
        ctx.font = '12px monospace';
\
        ctx.fillText(obj.mass + 'kg', obj.x - 14, obj.y + 4);
\

\
        ctx.restore();
\
      }
